INSERT INTO `book` VALUES
(9, 'Clean Code', 'Robert C. Martin', 'A classic guide to writing professional software that emphasizes readability, maintainability, clean architecture, refactoring techniques, coding standards, and best practices for long-term project success.', 5, 4, 'Backend', '/images/cleancode.jfif'),
(10, 'Eloquent JavaScript', 'Marijn Haverbeke', 'A modern and comprehensive introduction to JavaScript that explores language fundamentals, browser programming, asynchronous development, functional techniques, and practical software engineering concepts.', 4, 4, 'Frontend', '/images/ejs.png'),
(11, 'Learning React', 'Alex Banks & Eve Porcello', 'A practical guide to building modern user interfaces with React, covering components, hooks, state management, routing, application architecture, and efficient frontend development workflows.', 4, 3, 'Frontend', '/images/lreact.jfif'),
(12, 'Designing Data-Intensive Applications', 'Martin Kleppmann', 'An authoritative resource on distributed systems and large-scale applications, explaining databases, scalability, reliability, consistency, data processing architectures, and modern infrastructure design principles.', 5, 5, 'Data', '/images/ddia.jfif'),
(13, 'Python for Data Analysis', 'Wes McKinney', 'Learn professional data analysis techniques with Python using Pandas and NumPy, including data cleaning, transformation, visualization, exploration, and preparation for analytical workflows.', 5, 0, 'Data', '/images/pythondata.jfif'),
(14, 'The DevOps Handbook', 'Gene Kim, Jez Humble', 'A comprehensive DevOps guide that explains collaboration between development and operations teams, continuous delivery, automation strategies, reliability engineering, and organizational transformation practices.', 5, 5, 'DevOps', '/images/devh.jfif'),
(15, 'Kubernetes Up & Running', 'Kelsey Hightower, Brendan Burns', 'A practical introduction to Kubernetes covering container orchestration, deployment strategies, scaling techniques, cluster management, cloud-native development, and production-ready infrastructure practices.', 4, 4, 'DevOps', '/images/kuberur.jfif');